#[tokio::test]
async fn test_request_id_header_is_preserved() {
    // When the client supplies X-Request-ID the same value should appear on the response.
    let expected_body = r#"{"echo":"trace-123","status":"preserved"}"#.to_string();
    let mut app = spikard::App::new();
    app.route(
        spikard::get("/request-id/preserved"),
        move |_ctx: spikard::RequestContext| {
            let body = expected_body.clone();
            async move {
                Ok(axum::http::Response::builder()
                    .status(200u16)
                    .header("content-type", "application/json")
                    .body(axum::body::Body::from(body))
                    .unwrap())
            }
        },
    )
    .unwrap();
    let router = app.into_router().unwrap();
    let server = axum_test::TestServer::new(router);
    let response = server
        .get("/request-id/preserved")
        .add_header(r#"X-Request-ID"#, r#"trace-123"#)
        .await;
    assert_eq!(response.status_code().as_u16(), 200u16);
}

